const sharedAccessForUser = `-- name: SharedAccessForUser :one
WITH RECURSIVE chain(node_id, parent_id) AS (
    SELECT n.id, n.parent_id FROM nodes n WHERE n.id = $2
    UNION ALL
    SELECT n.id, n.parent_id FROM nodes n JOIN chain c ON n.id = c.parent_id
)
SELECT
    COALESCE(bool_or(rs.access = 'read_write'), false)::bool AS can_write,
    (count(rs.id) > 0)::bool AS can_read
FROM resource_shares rs
JOIN chain c ON rs.resource_id = c.node_id
WHERE rs.resource_type = 'file_node'
  AND rs.shared_with_user = $1
  AND (rs.expires_at IS NULL OR rs.expires_at > now())
`

type SharedAccessForUserParams struct {
	UserID  pgtype.UUID `json:"user_id"`
	StartID pgtype.UUID `json:"start_id"`
}

type SharedAccessForUserRow struct {
	CanWrite bool `json:"can_write"`
	CanRead  bool `json:"can_read"`
}

func (q *Queries) SharedAccessForUser(ctx context.Context, arg SharedAccessForUserParams) (SharedAccessForUserRow, error) {
	row := q.db.QueryRow(ctx, sharedAccessForUser, arg.UserID, arg.StartID)
	var i SharedAccessForUserRow
	err := row.Scan(&i.CanWrite, &i.CanRead)
	return i, err
}

